#include <stdio.h>
#include <string.h>
#include <stdlib.h>

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N, M;
        scanf("%d %d", &N, &M);
        char str[N + 1];
        scanf("%s", str);
        char dict[M][101];
        for (int i = 0; i < M; i++) {
            scanf("%s", dict[i]);
        }
        int dp[N + 1] = {0};
        char res[N + 1] = {0};
        for (int i = 1; i <= N; i++) {
            for (int j = 0; j < M; j++) {
                int len = strlen(dict[j]);
                if (i >= len) {
                    int match = 1;
                    for (int k = 0; k < len; k++) {
                        if (str[i - len + k] != '?' && str[i - len + k] != dict[j][k]) {
                            match = 0;
                            break;
                        }
                    }
                    if (match) {
                        if (dp[i - len] + 1 > dp[i]) {
                            dp[i] = dp[i - len] + 1;
                            strncpy(res + i - len, dict[j], len);
                        }
                    }
                }
            }
        }
        printf("%d\n", dp[N]);
        printf("%s\n", res);
    }
    return 0;
}

