        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            int N = sc.nextInt();
            int M = sc.nextInt();
            String str = sc.next();
            String[] dict = new String[M];
            for (int i = 0; i < M; i++) {
                dict[i] = sc.next();
            }
            int[] dp = new int[N + 1];
            String[] res = new String[N + 1];
            for (int i = 1; i <= N; i++) {
                for (int j = 0; j < M; j++) {
                    int len = dict[j].length();
                    if (i >= len) {
                        int match = 1;
                        for (int k = 0; k < len; k++) {
                            if (str.charAt(i - len + k) != '?' && str.charAt(i - len + k) != dict[j].charAt(k)) {
                                match = 0;
                                break;
                            }
                        }
                        if (match) {
                            if (dp[i - len] + 1 > dp[i]) {
                                dp[i] = dp[i - len] + 1;
                                res[i] = dict[j];
                            }
                        }
                    }
                }
            }
            System.out.println(dp[N]);
            System.out.println(res[N]);
        }
